import React from 'react'
import { useState } from 'react'
function Home() {
  let [counter, setCounter] = useState(0)
  const increament = () => {
    setCounter(counter + 1)
  }
  const decreament = () => {
    setCounter(counter - 1)
  }
  return (
    <div>
      <h1>Home</h1>
      <h2>{counter}</h2>
      <button onClick={increament}>Increament</button>
      <button onClick={decreament}>Decreament</button>
    </div>
  )
}

export default Home
